/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `car_variants` (
  `variant_id` bigint NOT NULL AUTO_INCREMENT,
  `model_id` int NOT NULL,
  `model_year` smallint NOT NULL,
  `trim_name` varchar(120) COLLATE utf8mb4_unicode_ci NOT NULL,
  `body_type` enum('sedan','hatchback','suv','cuv','mpv','pickup','coupe','convertible','wagon','van','other') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'other',
  `engine` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `transmission` varchar(60) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `drivetrain` varchar(60) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `fuel_type` enum('gasoline','diesel','hybrid','phev','ev','other') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'other',
  `seats` tinyint DEFAULT NULL,
  `doors` tinyint DEFAULT NULL,
  `msrp_base` decimal(14,2) DEFAULT NULL,
  `is_placeholder` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`variant_id`),
  UNIQUE KEY `uq_variant_unique` (`model_id`,`model_year`,`trim_name`),
  KEY `idx_variants_model` (`model_id`),
  KEY `idx_variants_year` (`model_year`),
  CONSTRAINT `fk_variants_model` FOREIGN KEY (`model_id`) REFERENCES `car_models` (`model_id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=23 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
