CREATE TABLE `data_freshness_snapshots` (
  `freshness_id` bigint NOT NULL AUTO_INCREMENT,
  `entity_type` varchar(80) COLLATE utf8mb4_unicode_ci NOT NULL,
  `entity_key` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `source_reference_id` bigint DEFAULT NULL,
  `last_refreshed_at` datetime NOT NULL,
  `freshness_days` int DEFAULT NULL,
  `status` enum('fresh','stale','expired','unknown') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'unknown',
  `notes` text COLLATE utf8mb4_unicode_ci,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`freshness_id`),
  UNIQUE KEY `uq_data_freshness` (`entity_type`,`entity_key`),
  KEY `fk_data_freshness_source` (`source_reference_id`),
  CONSTRAINT `fk_data_freshness_source` FOREIGN KEY (`source_reference_id`) REFERENCES `source_references` (`source_reference_id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=204 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
