  `provider_avatar_url` text COLLATE utf8mb4_unicode_ci,
  `provider_email_verified` tinyint(1) NOT NULL DEFAULT '0',
  `metadata_json` longtext COLLATE utf8mb4_unicode_ci,
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  PRIMARY KEY (`external_identity_id`),
  UNIQUE KEY `uniq_external_provider_user` (`provider_name`,`provider_user_id`),
  KEY `idx_external_user` (`user_id`),
  CONSTRAINT `external_identities_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
