--
-- Table structure for table `listings`
--

DROP TABLE IF EXISTS `listings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `listings` (
  `listing_id` bigint NOT NULL AUTO_INCREMENT,
  `owner_id` bigint NOT NULL,
  `variant_id` bigint NOT NULL,
  `asking_price` decimal(14,2) NOT NULL,
  `mileage_km` int DEFAULT NULL,
  `location_city` varchar(120) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `location_country_code` char(2) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'VN',
  `status` enum('active','reserved','sold','hidden') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'active',
  `description` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`listing_id`),
  KEY `idx_listings_owner` (`owner_id`),
  KEY `idx_listings_variant` (`variant_id`),
  KEY `idx_listings_status` (`status`),
  KEY `idx_listings_location` (`location_country_code`,`location_city`),
  CONSTRAINT `fk_listings_owner` FOREIGN KEY (`owner_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_listings_variant` FOREIGN KEY (`variant_id`) REFERENCES `car_variants` (`variant_id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=67 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

