--
-- Table structure for table `vehicle_market_signals`
--

DROP TABLE IF EXISTS `vehicle_market_signals`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `vehicle_market_signals` (
  `signal_id` bigint NOT NULL AUTO_INCREMENT,
  `variant_id` bigint NOT NULL,
  `market_id` int NOT NULL,
  `snapshot_date` datetime NOT NULL,
  `active_listing_count` int NOT NULL DEFAULT '0',
  `avg_asking_price` decimal(14,2) DEFAULT NULL,
  `median_asking_price` decimal(14,2) DEFAULT NULL,
  `min_asking_price` decimal(14,2) DEFAULT NULL,
  `max_asking_price` decimal(14,2) DEFAULT NULL,
  `avg_mileage_km` decimal(12,2) DEFAULT NULL,
  `price_spread_pct` decimal(10,6) DEFAULT NULL,
  `scarcity_score` decimal(10,6) DEFAULT NULL,
  `data_confidence` decimal(10,6) DEFAULT NULL,
  `source_reference_id` bigint DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`signal_id`),
  UNIQUE KEY `uq_vehicle_market_signal` (`variant_id`,`market_id`,`snapshot_date`),
  KEY `idx_vehicle_market_signal_lookup` (`variant_id`,`market_id`,`snapshot_date`),
  KEY `fk_vehicle_market_signal_market` (`market_id`),
  KEY `fk_vehicle_market_signal_source` (`source_reference_id`),
  CONSTRAINT `fk_vehicle_market_signal_market` FOREIGN KEY (`market_id`) REFERENCES `markets` (`market_id`) ON DELETE CASCADE,
  CONSTRAINT `fk_vehicle_market_signal_source` FOREIGN KEY (`source_reference_id`) REFERENCES `source_references` (`source_reference_id`) ON DELETE SET NULL,
  CONSTRAINT `fk_vehicle_market_signal_variant` FOREIGN KEY (`variant_id`) REFERENCES `car_variants` (`variant_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=39 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `vehicle_market_signals`
--

